.root-container {
    flex-grow: 1;
    align-items: center;
    justify-content: center;
    padding: 40px;
    background-color: rgba(30, 30, 46, 0.95);
}

.title {
    font-size: 36px;
    color: rgb(205, 214, 244);
    -unity-font-style: bold;
    margin-bottom: 30px;
}

.card {
    background-color: rgba(49, 50, 68, 0.9);
    border-radius: 12px;
    padding: 24px;
    margin-bottom: 16px;
    width: 400px;
    border-width: 1px;
    border-color: rgba(88, 91, 112, 0.5);
}

.card-title {
    font-size: 20px;
    color: rgb(205, 214, 244);
    -unity-font-style: bold;
    margin-bottom: 12px;
}

.counter-text {
    font-size: 28px;
    color: rgb(137, 180, 250);
    -unity-text-align: middle-center;
    margin-bottom: 16px;
}

.button-row {
    flex-direction: row;
    justify-content: center;
}

.btn {
    font-size: 18px;
    padding: 8px 24px;
    border-radius: 8px;
    margin: 0 8px;
    border-width: 0;
    -unity-font-style: bold;
}

.btn-primary {
    background-color: rgb(137, 180, 250);
    color: rgb(30, 30, 46);
}

.btn-primary:hover {
    background-color: rgb(116, 160, 230);
}

.btn-secondary {
    background-color: rgb(88, 91, 112);
    color: rgb(205, 214, 244);
}

.btn-secondary:hover {
    background-color: rgb(108, 111, 132);
}

.input-field {
    margin-bottom: 12px;
}

.greeting-text {
    font-size: 18px;
    color: rgb(166, 227, 161);
    -unity-text-align: middle-center;
    margin-top: 8px;
    min-height: 24px;
}

Toggle {
    margin-bottom: 8px;
}

SliderInt {
    margin-bottom: 8px;
}

DropdownField {
    margin-bottom: 4px;
}

