        // Create or find PanelSettings
        var panelSettingsGuids = AssetDatabase.FindAssets("t:PanelSettings", new[] { "Assets/UIToolkitSample" });
        PanelSettings panelSettings;

        if (panelSettingsGuids.Length > 0)
        {
            panelSettings = AssetDatabase.LoadAssetAtPath<PanelSettings>(
                AssetDatabase.GUIDToAssetPath(panelSettingsGuids[0]));
        }
        else
        {
            panelSettings = ScriptableObject.CreateInstance<PanelSettings>();
            panelSettings.scaleMode = PanelScaleMode.ScaleWithScreenSize;
            panelSettings.referenceResolution = new Vector2Int(1920, 1080);
            AssetDatabase.CreateAsset(panelSettings, "Assets/UIToolkitSample/SamplePanelSettings.asset");
        }

        // Find USS
        var ussGuids = AssetDatabase.FindAssets("SampleUI t:StyleSheet", new[] { "Assets/UIToolkitSample" });
        StyleSheet uss = null;
        if (ussGuids.Length > 0)
        {
            uss = AssetDatabase.LoadAssetAtPath<StyleSheet>(
                AssetDatabase.GUIDToAssetPath(ussGuids[0]));
        }

        // Create GameObject
        var go = new GameObject("UIToolkitSample");

        // Add UIDocument
        var uiDoc = go.AddComponent<UIDocument>();
        uiDoc.panelSettings = panelSettings;
        uiDoc.visualTreeAsset = uxml;

        // Add controller script
        go.AddComponent<SampleUIController>();

        // Add USS to panel settings default style if available
        if (uss != null)
        {
            panelSettings.themeStyleSheet = uss;
        }

        Undo.RegisterCreatedObjectUndo(go, "Create UIToolkit Sample");
        Selection.activeGameObject = go;

        Debug.Log("UIToolkit Sample scene setup complete! Press Play to test.");
    }
}

