/* Root layout */
.root {
    flex-direction: row;
    flex-grow: 1;
    background-color: rgb(250, 247, 240);
}

/* ===== Sidebar ===== */
.sidebar {
    width: 280px;
    background-color: rgb(245, 241, 233);
    border-right-width: 1px;
    border-right-color: rgb(225, 220, 210);
    padding: 12px;
    justify-content: flex-start;
}

.new-chat-btn {
    background-color: rgba(0, 0, 0, 0);
    border-width: 0;
    color: rgb(80, 80, 80);
    font-size: 14px;
    -unity-text-align: middle-left;
    padding: 8px 12px;
    margin-bottom: 4px;
}

.new-chat-btn:hover {
    background-color: rgba(0, 0, 0, 0.05);
    border-radius: 8px;
}

.section-label {
    font-size: 12px;
    color: rgb(140, 135, 125);
    padding: 12px 12px 4px 12px;
    -unity-font-style: normal;
}

.sidebar-item {
    background-color: rgba(0, 0, 0, 0);
    border-width: 0;
    color: rgb(60, 58, 53);
    font-size: 13px;
    -unity-text-align: middle-left;
    padding: 6px 12px;
    margin: 1px 0;
    border-radius: 6px;
    -unity-text-overflow-position: end;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.sidebar-item:hover {
    background-color: rgba(0, 0, 0, 0.05);
}

.search-item {
    color: rgb(100, 95, 88);
}

.favorites-scroll {
    flex-grow: 1;
}

/* User profile */
.user-profile {
    flex-direction: row;
    align-items: center;
    padding: 12px;
    border-top-width: 1px;
    border-top-color: rgb(225, 220, 210);
    margin-top: 8px;
}

.user-avatar {
    width: 32px;
    height: 32px;
    border-radius: 16px;
    background-color: rgb(100, 100, 110);
    align-items: center;
    justify-content: center;
    margin-right: 8px;
}

.avatar-text {
    color: white;
    font-size: 14px;
    -unity-font-style: bold;
}

.user-name {
    font-size: 13px;
    color: rgb(40, 38, 35);
    -unity-font-style: bold;
}

.user-plan {
    font-size: 11px;
    color: rgb(140, 135, 125);
}

/* ===== Main content ===== */
.main-content {
    flex-grow: 1;
    background-color: rgb(255, 255, 255);
}

/* Top bar */
.top-bar {
    height: 48px;
    border-bottom-width: 1px;
    border-bottom-color: rgb(235, 232, 225);
    align-items: center;
    justify-content: center;
    flex-direction: row;
}

.tab-group {
    flex-direction: row;
    background-color: rgb(242, 240, 235);
    border-radius: 8px;
    padding: 3px;
}

.tab-btn {
    background-color: rgba(0, 0, 0, 0);
    border-width: 0;
    color: rgb(120, 115, 108);
    font-size: 13px;
    padding: 5px 16px;
    border-radius: 6px;
    margin: 0;
}

.tab-btn:hover {
    color: rgb(60, 58, 53);
}

.tab-active {
    background-color: rgb(255, 255, 255);
    color: rgb(40, 38, 35);
    -unity-font-style: bold;
}

/* Chat area */
.chat-area {
    flex-grow: 1;
    padding: 24px 80px;
}

/* Message styles */
.message-row {
    margin-bottom: 16px;
}

.user-row {
    align-items: flex-end;
}

.assistant-row {
    align-items: flex-start;
}

.message-bubble {
    max-width: 520px;
    padding: 12px 16px;
    border-radius: 16px;
}

.user-bubble {
    background-color: rgb(242, 240, 235);
}

.assistant-bubble {
    background-color: rgba(0, 0, 0, 0);
    padding-left: 0;
}

.message-text {
    font-size: 14px;
    color: rgb(40, 38, 35);
    white-space: normal;
    margin-bottom: 4px;
}

.message-meta {
    font-size: 13px;
    color: rgb(140, 135, 125);
    margin-bottom: 8px;
}

.bold-text {
    -unity-font-style: bold;
    margin-bottom: 8px;
}

.bullet-text {
    padding-left: 16px;
    margin-bottom: 4px;
}

.body-text {
    margin-top: 8px;
    line-height: 1.5;
}

/* Input area */
.input-area {
    padding: 12px 80px 24px 80px;
    border-top-width: 1px;
    border-top-color: rgb(240, 238, 232);
}

.input-container {
    flex-direction: row;
    align-items: center;
    background-color: rgb(250, 248, 244);
    border-radius: 16px;
    border-width: 1px;
    border-color: rgb(225, 220, 210);
    padding: 8px 12px;
}

.chat-input {
    flex-grow: 1;
    background-color: rgba(0, 0, 0, 0);
    border-width: 0;
    font-size: 14px;
    color: rgb(40, 38, 35);
}

.chat-input > .unity-text-field__input {
    background-color: rgba(0, 0, 0, 0);
    border-width: 0;
    padding: 4px 8px;
}

.model-label {
    font-size: 12px;
    color: rgb(140, 135, 125);
    margin-right: 8px;
}

.send-btn {
    width: 32px;
    height: 32px;
    border-radius: 16px;
    background-color: rgb(200, 120, 80);
    color: white;
    font-size: 16px;
    -unity-font-style: bold;
    border-width: 0;
    align-items: center;
    justify-content: center;
}

.send-btn:hover {
    background-color: rgb(180, 105, 70);
}

