using UnityEngine;
using UnityEngine.UIElements;

public class ChatUIController : MonoBehaviour
{
    private ScrollView chatScroll;
    private TextField chatInput;

    void OnEnable()
    {
        var root = GetComponent<UIDocument>().rootVisualElement;

        chatScroll = root.Q<ScrollView>("chat-scroll");
        chatInput = root.Q<TextField>("chat-input");

        // Send button
        root.Q<Button>("send-btn").clicked += SendMessage;

        // Enter key to send
        chatInput.RegisterCallback<KeyDownEvent>(evt =>
        {
            if (evt.keyCode == KeyCode.Return && !evt.shiftKey)
            {
                evt.StopPropagation();
                evt.PreventDefault();
                SendMessage();
            }
        });

        // New chat button
        root.Q<Button>("new-chat-btn").clicked += () =>
        {
            chatScroll.Clear();
            Debug.Log("New chat started");
        };

        // Tab switching
        var tabs = root.Query<Button>(className: "tab-btn").ToList();
        foreach (var tab in tabs)
        {
            tab.clicked += () =>
            {
                foreach (var t in tabs)
                    t.RemoveFromClassList("tab-active");
                tab.AddToClassList("tab-active");
            };
        }

        // Sidebar favorites
        var favItems = root.Query<Button>(className: "fav-item").ToList();
        foreach (var item in favItems)
        {
            var itemRef = item;
            item.clicked += () => Debug.Log($"Selected: {itemRef.text}");
        }
    }

    private void SendMessage()
    {
        var text = chatInput.value?.Trim();
        if (string.IsNullOrEmpty(text)) return;

        // Add user message
        var userRow = new VisualElement();
        userRow.AddToClassList("message-row");
        userRow.AddToClassList("user-row");

        var userBubble = new VisualElement();
        userBubble.AddToClassList("message-bubble");
        userBubble.AddToClassList("user-bubble");

        var userLabel = new Label(text);
        userLabel.AddToClassList("message-text");

        userBubble.Add(userLabel);
        userRow.Add(userBubble);
        chatScroll.Add(userRow);

        // Add mock assistant response
        var assistantRow = new VisualElement();
        assistantRow.AddToClassList("message-row");
        assistantRow.AddToClassList("assistant-row");

        var assistantBubble = new VisualElement();
        assistantBubble.AddToClassList("message-bubble");
        assistantBubble.AddToClassList("assistant-bubble");

        var responseLabel = new Label($"받았습니다: \"{text}\"");
        responseLabel.AddToClassList("message-text");

        assistantBubble.Add(responseLabel);
        assistantRow.Add(assistantBubble);
        chatScroll.Add(assistantRow);

        chatInput.value = "";
        chatInput.Focus();

        // Scroll to bottom
        chatScroll.schedule.Execute(() =>
            chatScroll.scrollOffset = new Vector2(0, float.MaxValue));
    }
}

