using UnityEditor;
using UnityEngine;
using UnityEngine.UIElements;

public static class ChatUISceneSetup
{
    [MenuItem("Tools/Setup ChatUI Scene")]
    public static void SetupScene()
    {
        var uxmlGuids = AssetDatabase.FindAssets("ChatUI t:VisualTreeAsset");
        if (uxmlGuids.Length == 0)
        {
            Debug.LogError("ChatUI.uxml not found!");
            return;
        }

        var uxml = AssetDatabase.LoadAssetAtPath<VisualTreeAsset>(
            AssetDatabase.GUIDToAssetPath(uxmlGuids[0]));

        // Create or find PanelSettings
        var panelGuids = AssetDatabase.FindAssets("t:PanelSettings", new[] { "Assets/ChatUI" });
        PanelSettings panelSettings;

        if (panelGuids.Length > 0)
        {
            panelSettings = AssetDatabase.LoadAssetAtPath<PanelSettings>(
                AssetDatabase.GUIDToAssetPath(panelGuids[0]));
        }
        else
        {
            panelSettings = ScriptableObject.CreateInstance<PanelSettings>();
            panelSettings.scaleMode = PanelScaleMode.ScaleWithScreenSize;
            panelSettings.referenceResolution = new Vector2Int(1920, 1080);
            AssetDatabase.CreateAsset(panelSettings, "Assets/ChatUI/ChatPanelSettings.asset");
        }

        var go = new GameObject("ChatUI");
        var uiDoc = go.AddComponent<UIDocument>();
        uiDoc.panelSettings = panelSettings;
        uiDoc.visualTreeAsset = uxml;
        go.AddComponent<ChatUIController>();

        Undo.RegisterCreatedObjectUndo(go, "Create ChatUI");
        Selection.activeGameObject = go;

        Debug.Log("ChatUI scene setup complete! Press Play to test.");
    }
}

