using UnityEngine;
using UnityEngine.UIElements;

/// <summary>
/// uGUI 드래그 → UI Toolkit 드롭 브릿지.
/// 마우스 위치가 UI Toolkit 드롭존 위에 있으면 아이템을 받아서 그린다.
/// </summary>
public class UGUIToUIToolkitBridge : MonoBehaviour
{
    private UIDocument uiDocument;
    private VisualElement dropZone;
    private VisualElement dropHint;

    void OnEnable()
    {
        uiDocument = GetComponent<UIDocument>();
        var root = uiDocument.rootVisualElement;

        dropZone = root.Q<VisualElement>("drop-zone");
        dropHint = root.Q<VisualElement>("drop-hint");
    }

    /// <summary>
    /// uGUI의 OnEndDrag에서 호출. 스크린 좌표를 UI Toolkit 좌표로 변환하여
    /// 드롭존 위에 있으면 아이템을 추가한다.
    /// </summary>
    public bool TryDropItem(Vector2 screenPosition, string itemName, Color color)
    {
        if (dropZone == null) return false;

        // Screen → Panel 좌표 변환
        // UI Toolkit은 좌상단 원점, uGUI Screen은 좌하단 원점
        var panelPosition = new Vector2(screenPosition.x, Screen.height - screenPosition.y);

        // RuntimePanelUtils로 정확한 좌표 변환
        var localPos = RuntimePanelUtils.ScreenToPanel(
            uiDocument.rootVisualElement.panel, screenPosition);

        // 드롭존 영역 체크
        var worldBound = dropZone.worldBound;
        if (!worldBound.Contains(localPos))
            return false;

        // 아이템을 UI Toolkit에 생성
        AddItemToDropZone(itemName, color);

        // 힌트 숨기기
        if (dropHint != null)
            dropHint.style.display = DisplayStyle.None;

        return true;
    }

    private void AddItemToDropZone(string itemName, Color color)
    {
        var itemCard = new VisualElement();
        itemCard.AddToClassList("dropped-item");
        itemCard.style.backgroundColor = new StyleColor(color);

        var label = new Label(itemName);
        label.AddToClassList("dropped-item-label");

        var badge = new Label("from uGUI");
        badge.AddToClassList("dropped-item-badge");

        itemCard.Add(label);
        itemCard.Add(badge);

        dropZone.Add(itemCard);

        Debug.Log($"[Bridge] Item '{itemName}' transferred from uGUI → UI Toolkit");
    }
}

