.root {
    flex-direction: row;
    flex-grow: 1;
    /* 왼쪽 절반은 비워둠 - uGUI Canvas가 차지 */
    justify-content: flex-end;
}

.right-panel {
    width: 50%;
    background-color: rgba(30, 30, 46, 0.92);
    padding: 24px;
}

.panel-title {
    font-size: 24px;
    color: rgb(205, 214, 244);
    -unity-font-style: bold;
    margin-bottom: 4px;
}

.panel-subtitle {
    font-size: 13px;
    color: rgb(140, 143, 161);
    margin-bottom: 16px;
}

.drop-zone {
    flex-grow: 1;
    background-color: rgba(49, 50, 68, 0.6);
    border-radius: 12px;
    border-width: 2px;
    border-color: rgba(137, 180, 250, 0.3);
    padding: 16px;
    flex-direction: row;
    flex-wrap: wrap;
    align-content: flex-start;
}

.drop-hint {
    width: 100%;
    height: 80px;
    border-radius: 8px;
    border-width: 2px;
    border-color: rgba(137, 180, 250, 0.4);
    align-items: center;
