18→
19→    void Awake()
20→    {
21→        rectTransform = GetComponent<RectTransform>();
22→        canvasGroup = GetComponent<CanvasGroup>();
23→        if (canvasGroup == null)
24→            canvasGroup = gameObject.AddComponent<CanvasGroup>();
25→        canvas = GetComponentInParent<Canvas>();
26→    }
27→
28→    public void OnBeginDrag(PointerEventData eventData)
29→    {
30→        originalPosition = rectTransform.anchoredPosition;
31→        originalParent = transform.parent;
32→        canvasGroup.alpha = 0.6f;
