using UnityEditor;
using UnityEngine;
using UnityEngine.UI;
using UnityEngine.UIElements;

public static class DragDropBridgeSetup
{
    [MenuItem("Tools/Setup DragDrop Bridge Scene")]
    public static void SetupScene()
    {
        // ===== 1. UI Toolkit (오른쪽 절반) =====
        var uxmlGuids = AssetDatabase.FindAssets("DropZoneUI t:VisualTreeAsset");
        if (uxmlGuids.Length == 0)
        {
            Debug.LogError("DropZoneUI.uxml not found!");
            return;
        }
        var uxml = AssetDatabase.LoadAssetAtPath<VisualTreeAsset>(
            AssetDatabase.GUIDToAssetPath(uxmlGuids[0]));

        var panelGuids = AssetDatabase.FindAssets("t:PanelSettings", new[] { "Assets/DragDropBridge" });
        PanelSettings panelSettings;
        if (panelGuids.Length > 0)
        {
            panelSettings = AssetDatabase.LoadAssetAtPath<PanelSettings>(
                AssetDatabase.GUIDToAssetPath(panelGuids[0]));
        }
        else
        {
            panelSettings = ScriptableObject.CreateInstance<PanelSettings>();
            panelSettings.scaleMode = PanelScaleMode.ScaleWithScreenSize;
            panelSettings.referenceResolution = new Vector2Int(1920, 1080);
            panelSettings.sortingOrder = 0; // Behind uGUI during drag
            AssetDatabase.CreateAsset(panelSettings, "Assets/DragDropBridge/DropZonePanelSettings.asset");
        }

        var uitkGo = new GameObject("DropZone_UIToolkit");
        var uiDoc = uitkGo.AddComponent<UIDocument>();
        uiDoc.panelSettings = panelSettings;
        uiDoc.visualTreeAsset = uxml;
        uitkGo.AddComponent<UGUIToUIToolkitBridge>();
        Undo.RegisterCreatedObjectUndo(uitkGo, "Create DropZone UIToolkit");

        // ===== 2. uGUI Canvas (왼쪽 절반) =====
        var canvasGo = new GameObject("Inventory_uGUI");
        var canvas = canvasGo.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        canvas.sortingOrder = 10; // Above UI Toolkit
        canvasGo.AddComponent<CanvasScaler>().uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        canvasGo.GetComponent<CanvasScaler>().referenceResolution = new Vector2(1920, 1080);
        canvasGo.AddComponent<GraphicRaycaster>();
        Undo.RegisterCreatedObjectUndo(canvasGo, "Create Inventory Canvas");

        // Background panel (왼쪽 절반)
        var panelGo = CreateUIElement("InventoryPanel", canvasGo.transform);
        var panelRect = panelGo.GetComponent<RectTransform>();
        panelRect.anchorMin = new Vector2(0, 0);
        panelRect.anchorMax = new Vector2(0.48f, 1);
        panelRect.offsetMin = Vector2.zero;
        panelRect.offsetMax = Vector2.zero;
        var panelImg = panelGo.AddComponent<UnityEngine.UI.Image>();
        panelImg.color = new Color(0.95f, 0.93f, 0.88f, 1f);

        // Title
        var titleGo = CreateUIElement("Title", panelGo.transform);
        var titleRect = titleGo.GetComponent<RectTransform>();
        titleRect.anchorMin = new Vector2(0, 1);
        titleRect.anchorMax = new Vector2(1, 1);
        titleRect.pivot = new Vector2(0.5f, 1);
        titleRect.sizeDelta = new Vector2(0, 60);
        titleRect.anchoredPosition = new Vector2(0, -10);
        var titleText = titleGo.AddComponent<Text>();
        titleText.text = "uGUI Inventory";
        titleText.fontSize = 28;
        titleText.alignment = TextAnchor.MiddleCenter;
        titleText.color = new Color(0.2f, 0.2f, 0.2f);
        titleText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        var subtitleGo = CreateUIElement("Subtitle", panelGo.transform);
        var subRect = subtitleGo.GetComponent<RectTransform>();
        subRect.anchorMin = new Vector2(0, 1);
        subRect.anchorMax = new Vector2(1, 1);
        subRect.pivot = new Vector2(0.5f, 1);
        subRect.sizeDelta = new Vector2(0, 30);
        subRect.anchoredPosition = new Vector2(0, -65);
        var subText = subtitleGo.AddComponent<Text>();
        subText.text = "아이템을 오른쪽으로 드래그하세요 →";
        subText.fontSize = 16;
        subText.alignment = TextAnchor.MiddleCenter;
        subText.color = new Color(0.5f, 0.48f, 0.45f);
        subText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Grid of draggable items
        var gridGo = CreateUIElement("ItemGrid", panelGo.transform);
        var gridRect = gridGo.GetComponent<RectTransform>();
        gridRect.anchorMin = new Vector2(0, 0);
        gridRect.anchorMax = new Vector2(1, 1);
        gridRect.offsetMin = new Vector2(30, 30);
        gridRect.offsetMax = new Vector2(-30, -100);
        var grid = gridGo.AddComponent<GridLayoutGroup>();
        grid.cellSize = new Vector2(120, 120);
        grid.spacing = new Vector2(16, 16);
        grid.padding = new RectOffset(10, 10, 10, 10);

        // Create sample items
        var items = new (string name, Color color)[]
        {
            ("Sword", new Color(0.85f, 0.32f, 0.32f)),
            ("Shield", new Color(0.35f, 0.55f, 0.85f)),
            ("Potion", new Color(0.35f, 0.78f, 0.45f)),
            ("Scroll", new Color(0.82f, 0.72f, 0.35f)),
            ("Ring", new Color(0.7f, 0.45f, 0.82f)),
            ("Gem", new Color(0.3f, 0.82f, 0.78f)),
        };

        foreach (var (name, color) in items)
        {
            var itemGo = CreateUIElement(name, gridGo.transform);
            var itemRect = itemGo.GetComponent<RectTransform>();
            var itemImg = itemGo.AddComponent<UnityEngine.UI.Image>();
            itemImg.color = color;

            // Rounded look
            itemGo.AddComponent<Outline>().effectColor = new Color(0, 0, 0, 0.15f);

            // Label
            var labelGo = CreateUIElement("Label", itemGo.transform);
            var labelRect = labelGo.GetComponent<RectTransform>();
            labelRect.anchorMin = Vector2.zero;
            labelRect.anchorMax = Vector2.one;
            labelRect.offsetMin = Vector2.zero;
            labelRect.offsetMax = Vector2.zero;
            var labelText = labelGo.AddComponent<Text>();
            labelText.text = name;
            labelText.fontSize = 18;
            labelText.alignment = TextAnchor.MiddleCenter;
            labelText.color = Color.white;
            labelText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

            // DraggableItem component
            var draggable = itemGo.AddComponent<DraggableItem>();
            draggable.itemName = name;
            draggable.itemColor = color;
        }

        // ===== 3. EventSystem =====
        if (Object.FindFirstObjectByType<UnityEngine.EventSystems.EventSystem>() == null)
        {
            var esGo = new GameObject("EventSystem");
            esGo.AddComponent<UnityEngine.EventSystems.EventSystem>();
            esGo.AddComponent<UnityEngine.EventSystems.StandaloneInputModule>();
            Undo.RegisterCreatedObjectUndo(esGo, "Create EventSystem");
        }

        // ===== 4. Camera =====
        if (Camera.main == null)
        {
            var camGo = new GameObject("Main Camera");
            camGo.tag = "MainCamera";
            var cam = camGo.AddComponent<Camera>();
            cam.orthographic = true;
            cam.backgroundColor = new Color(0.15f, 0.15f, 0.2f);
            cam.transform.position = new Vector3(0, 0, -10);
            Undo.RegisterCreatedObjectUndo(camGo, "Create Camera");
        }

        Selection.activeGameObject = canvasGo;
        Debug.Log("DragDrop Bridge scene setup complete! Press Play to test.");
    }

    private static GameObject CreateUIElement(string name, Transform parent)
    {
        var go = new GameObject(name, typeof(RectTransform));
        go.transform.SetParent(parent, false);
        return go;
    }
}

