using UnityEngine;
using UnityEngine.UI;
using UnityEngine.UIElements;

/// <summary>
/// UI Toolkit → uGUI 역방향 브릿지.
/// 드롭존의 아이템을 드래그해서 uGUI 인벤토리에 놓으면 이동.
/// </summary>
public class UIToolkitToUGUIBridge : MonoBehaviour
{
    private UIDocument uiDocument;
    private VisualElement dropZone;
    private VisualElement dragGhost;
    private VisualElement dragTarget;
    private string dragItemName;
    private Color dragItemColor;
    private bool isDragging;

    void OnEnable()
    {
        uiDocument = GetComponent<UIDocument>();
        var root = uiDocument.rootVisualElement;
        dropZone = root.Q<VisualElement>("drop-zone");

        // 드래그용 고스트 (반투명 복제본)
        dragGhost = new VisualElement();
        dragGhost.AddToClassList("drag-ghost");
        dragGhost.style.display = DisplayStyle.None;
        dragGhost.style.position = Position.Absolute;
        dragGhost.pickingMode = PickingMode.Ignore;
        root.Add(dragGhost);

        // 드롭존 아이템에 마우스 이벤트 등록
        dropZone.RegisterCallback<PointerDownEvent>(OnPointerDown);
        root.RegisterCallback<PointerMoveEvent>(OnPointerMove);
        root.RegisterCallback<PointerUpEvent>(OnPointerUp);
    }

    private void OnPointerDown(PointerDownEvent evt)
    {
        // dropped-item 클래스를 가진 요소를 찾기
        var target = evt.target as VisualElement;
        while (target != null && !target.ClassListContains("dropped-item"))
            target = target.parent;

        if (target == null) return;

        dragTarget = target;
        dragItemName = target.Q<Label>(className: "dropped-item-label")?.text ?? "Item";
        dragItemColor = target.resolvedStyle.backgroundColor;
        isDragging = true;

        // 고스트 세팅
        dragGhost.style.width = 100;
        dragGhost.style.height = 100;
        dragGhost.style.backgroundColor = new StyleColor(dragItemColor);
        dragGhost.style.opacity = 0.7f;
        dragGhost.style.borderTopLeftRadius = 10;
        dragGhost.style.borderTopRightRadius = 10;
        dragGhost.style.borderBottomLeftRadius = 10;
        dragGhost.style.borderBottomRightRadius = 10;
        dragGhost.style.display = DisplayStyle.Flex;
        dragGhost.style.alignItems = Align.Center;
        dragGhost.style.justifyContent = Justify.Center;

        dragGhost.Clear();
        var label = new Label(dragItemName);
        label.style.color = Color.white;
        label.style.fontSize = 13;
        label.pickingMode = PickingMode.Ignore;
        dragGhost.Add(label);

        var panelPos = RuntimePanelUtils.ScreenToPanel(
            uiDocument.rootVisualElement.panel,
            new Vector2(evt.position.x, Screen.height - evt.position.y));
        dragGhost.style.left = panelPos.x - 50;
        dragGhost.style.top = panelPos.y - 50;

        dragTarget.style.opacity = 0.3f;

        evt.StopPropagation();
        target.CapturePointer(evt.pointerId);
    }

    private void OnPointerMove(PointerMoveEvent evt)
    {
        if (!isDragging) return;

        var panelPos = RuntimePanelUtils.ScreenToPanel(
            uiDocument.rootVisualElement.panel,
            new Vector2(evt.position.x, Screen.height - evt.position.y));
        dragGhost.style.left = panelPos.x - 50;
        dragGhost.style.top = panelPos.y - 50;
    }

    private void OnPointerUp(PointerUpEvent evt)
    {
        if (!isDragging) return;
        isDragging = false;
        dragGhost.style.display = DisplayStyle.None;

        if (dragTarget != null)
            dragTarget.ReleasePointer(evt.pointerId);

        // uGUI 인벤토리 영역 체크 (화면 왼쪽 48%)
        var screenPos = new Vector2(evt.position.x, Screen.height - evt.position.y);
        float normalizedX = screenPos.x / Screen.width;

        if (normalizedX < 0.48f)
        {
            // uGUI 영역에 드롭 — uGUI 아이템 생성
            CreateUGUIItem(dragItemName, dragItemColor);

            // UI Toolkit에서 제거
            if (dragTarget != null)
            {
                dragTarget.RemoveFromHierarchy();
                Debug.Log($"[Bridge] Item '{dragItemName}' transferred from UI Toolkit → uGUI");
            }

            // 드롭존이 비었으면 힌트 다시 표시
            var hint = dropZone.Q<VisualElement>("drop-hint");
            bool hasItems = false;
            foreach (var child in dropZone.Children())
            {
                if (child.ClassListContains("dropped-item"))
                {
                    hasItems = true;
                    break;
                }
            }
            if (!hasItems && hint != null)
                hint.style.display = DisplayStyle.Flex;
        }
        else
        {
            // 드롭 취소 — 원래대로
            if (dragTarget != null)
                dragTarget.style.opacity = 1f;
        }

        dragTarget = null;
    }

    private void CreateUGUIItem(string itemName, Color color)
    {
        // uGUI Canvas의 ItemGrid 찾기
        var canvas = FindFirstObjectByType<Canvas>();
        if (canvas == null) return;

        var grid = canvas.GetComponentInChildren<GridLayoutGroup>();
        if (grid == null) return;

        // 아이템 생성
        var itemGo = new GameObject(itemName, typeof(RectTransform));
        itemGo.transform.SetParent(grid.transform, false);

        var img = itemGo.AddComponent<UnityEngine.UI.Image>();
        img.color = color;
        itemGo.AddComponent<Outline>().effectColor = new Color(0, 0, 0, 0.15f);

        // 라벨
        var labelGo = new GameObject("Label", typeof(RectTransform));
        labelGo.transform.SetParent(itemGo.transform, false);
        var labelRect = labelGo.GetComponent<RectTransform>();
        labelRect.anchorMin = Vector2.zero;
