using UnityEngine;
using UnityEngine.UI;
using UnityEngine.UIElements;
using Image = UnityEngine.UI.Image;

/// <summary>
/// UI Toolkit → uGUI 역방향 브릿지.
/// 드래그 시 uGUI 고스트를 생성하여 전체 화면에서 자유롭게 이동.
/// </summary>
public class UIToolkitToUGUIBridge : MonoBehaviour
{
    private UIDocument uiDocument;
    private VisualElement root;
    private VisualElement dropZone;

    // 드래그 상태
    private VisualElement dragTarget;
    private string dragItemName;
    private Color dragItemColor;
    private bool isDragging;
    private int activePointerId = -1;

    // uGUI 고스트 (전체 화면에서 렌더링 가능)
    private Canvas ghostCanvas;
    private GameObject ghostGo;

    void OnEnable()
    {
        uiDocument = GetComponent<UIDocument>();
        root = uiDocument.rootVisualElement;
        dropZone = root.Q<VisualElement>("drop-zone");

        root.RegisterCallback<PointerDownEvent>(OnPointerDown, TrickleDown.TrickleDown);
        root.RegisterCallback<PointerMoveEvent>(OnPointerMove, TrickleDown.TrickleDown);
        root.RegisterCallback<PointerUpEvent>(OnPointerUp, TrickleDown.TrickleDown);
    }

    void OnDisable()
    {
        DestroyGhost();
    }

    private void OnPointerDown(PointerDownEvent evt)
    {
        if (isDragging) return;

        var target = evt.target as VisualElement;
        while (target != null && !target.ClassListContains("dropped-item"))
            target = target.parent;

        if (target == null || !dropZone.Contains(target)) return;

        dragTarget = target;
        dragItemName = target.Q<Label>(className: "dropped-item-label")?.text ?? "Item";
        dragItemColor = target.resolvedStyle.backgroundColor;
        isDragging = true;
        activePointerId = evt.pointerId;

        dragTarget.style.opacity = 0.3f;

        // uGUI 고스트 생성 — 별도 Canvas(sortingOrder 최상위)
        CreateGhost();
        UpdateGhostScreenPosition(Input.mousePosition);

        root.CapturePointer(evt.pointerId);
        evt.StopPropagation();
    }

    private void OnPointerMove(PointerMoveEvent evt)
    {
        if (!isDragging || evt.pointerId != activePointerId) return;

        UpdateGhostScreenPosition(Input.mousePosition);
        evt.StopPropagation();
    }

    private void OnPointerUp(PointerUpEvent evt)
    {
        if (!isDragging || evt.pointerId != activePointerId) return;

        isDragging = false;
        DestroyGhost();

        if (root.HasPointerCapture(evt.pointerId))
            root.ReleasePointer(evt.pointerId);

        // uGUI 인벤토리 영역 체크 (화면 왼쪽 48%)
        float normalizedX = Input.mousePosition.x / Screen.width;

        if (normalizedX < 0.48f)
        {
            CreateUGUIItem(dragItemName, dragItemColor);

            if (dragTarget != null)
            {
                dragTarget.RemoveFromHierarchy();
                Debug.Log($"[Bridge] Item '{dragItemName}' transferred from UI Toolkit → uGUI");
            }

            ShowHintIfEmpty();
        }
        else
        {
            if (dragTarget != null)
                dragTarget.style.opacity = 1f;
        }

        dragTarget = null;
        activePointerId = -1;
        evt.StopPropagation();
    }

    private void CreateGhost()
    {
        // 고스트 전용 Canvas (최상위 sortingOrder)
        var canvasGo = new GameObject("DragGhostCanvas");
        ghostCanvas = canvasGo.AddComponent<Canvas>();
        ghostCanvas.renderMode = RenderMode.ScreenSpaceOverlay;
        ghostCanvas.sortingOrder = 999;
        canvasGo.AddComponent<CanvasScaler>();

        // 고스트 아이템
        ghostGo = new GameObject("Ghost", typeof(RectTransform));
        ghostGo.transform.SetParent(canvasGo.transform, false);

        var rect = ghostGo.GetComponent<RectTransform>();
        rect.sizeDelta = new Vector2(100, 100);

        var img = ghostGo.AddComponent<Image>();
        img.color = new Color(dragItemColor.r, dragItemColor.g, dragItemColor.b, 0.7f);

        // 라벨
        var labelGo = new GameObject("Label", typeof(RectTransform));
        labelGo.transform.SetParent(ghostGo.transform, false);
        var labelRect = labelGo.GetComponent<RectTransform>();
        labelRect.anchorMin = Vector2.zero;
        labelRect.anchorMax = Vector2.one;
        labelRect.offsetMin = Vector2.zero;
        labelRect.offsetMax = Vector2.zero;

        var text = labelGo.AddComponent<Text>();
        text.text = dragItemName;
        text.fontSize = 16;
        text.alignment = TextAnchor.MiddleCenter;
        text.color = Color.white;
        text.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Raycast 차단 안 함
        img.raycastTarget = false;
        var cg = ghostGo.AddComponent<CanvasGroup>();
        cg.blocksRaycasts = false;
    }

    private void UpdateGhostScreenPosition(Vector3 mousePos)
    {
        if (ghostGo == null) return;
        var rect = ghostGo.GetComponent<RectTransform>();
        rect.position = mousePos;
    }

    private void DestroyGhost()
    {
        if (ghostCanvas != null)
        {
            Destroy(ghostCanvas.gameObject);
            ghostCanvas = null;
            ghostGo = null;
        }
    }

    private void ShowHintIfEmpty()
    {
        var hint = dropZone.Q<VisualElement>("drop-hint");
        if (hint == null) return;

        bool hasItems = false;
        foreach (var child in dropZone.Children())
        {
            if (child.ClassListContains("dropped-item"))
            {
                hasItems = true;
                break;
            }
        }
        if (!hasItems)
            hint.style.display = DisplayStyle.Flex;
    }

    private void CreateUGUIItem(string itemName, Color color)
    {
        // 기존 인벤토리 Canvas의 GridLayout 찾기
        foreach (var canvas in FindObjectsByType<Canvas>(FindObjectsSortMode.None))
        {
            if (canvas.sortingOrder == 999) continue; // 고스트 캔버스 스킵
            var grid = canvas.GetComponentInChildren<GridLayoutGroup>();
            if (grid == null) continue;

            var itemGo = new GameObject(itemName, typeof(RectTransform));
            itemGo.transform.SetParent(grid.transform, false);

            var img = itemGo.AddComponent<Image>();
            img.color = color;
            itemGo.AddComponent<Outline>().effectColor = new Color(0, 0, 0, 0.15f);

            var labelGo = new GameObject("Label", typeof(RectTransform));
            labelGo.transform.SetParent(itemGo.transform, false);
            var labelRect = labelGo.GetComponent<RectTransform>();
            labelRect.anchorMin = Vector2.zero;
            labelRect.anchorMax = Vector2.one;
            labelRect.offsetMin = Vector2.zero;
            labelRect.offsetMax = Vector2.zero;

            var text = labelGo.AddComponent<Text>();
            text.text = itemName;
            text.fontSize = 18;
            text.alignment = TextAnchor.MiddleCenter;
            text.color = Color.white;
            text.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

            var draggable = itemGo.AddComponent<DraggableItem>();
            draggable.itemName = itemName;
            draggable.itemColor = color;
            return;
        }
    }
}

