using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// uGUI DockSlot의 우하단 핸들을 드래그해서 리사이즈.
/// UI Toolkit이 자동으로 따라가는지 테스트용.
/// </summary>
public class DockSlotResizer : MonoBehaviour, IBeginDragHandler, IDragHandler, IEndDragHandler
{
    [SerializeField] private RectTransform targetSlot;

    private Canvas canvas;
    private Image handleImage;
    private Color normalColor = new Color(0.5f, 0.55f, 0.7f, 0.8f);
    private Color dragColor = new Color(0.54f, 0.71f, 0.98f, 1f);

    void Awake()
    {
        canvas = GetComponentInParent<Canvas>();
        handleImage = GetComponent<Image>();
    }

    public void OnBeginDrag(PointerEventData eventData)
    {
        if (handleImage != null) handleImage.color = dragColor;
    }

    public void OnDrag(PointerEventData eventData)
    {
        if (targetSlot == null) return;

        Vector2 delta = eventData.delta / canvas.scaleFactor;

        // 우하단 드래그 → 크기 변경
        var size = targetSlot.sizeDelta;
        size.x = Mathf.Max(200, size.x + delta.x);
        size.y = Mathf.Max(150, size.y - delta.y); // y는 반대
        targetSlot.sizeDelta = size;
    }

    public void OnEndDrag(PointerEventData eventData)
    {
        if (handleImage != null) handleImage.color = normalColor;
    }
}

