.root {
    flex-grow: 1;
    background-color: rgba(0, 0, 0, 0);
}

.dock-container {
    position: absolute;
    background-color: rgba(30, 30, 46, 0.95);
    border-radius: 8px;
    overflow: hidden;
    border-width: 1px;
    border-color: rgba(137, 180, 250, 0.3);
}

/* 드래그 타이틀바 */
.title-bar {
    height: 28px;
    background-color: rgba(49, 50, 68, 0.95);
    align-items: center;
    justify-content: center;
    border-bottom-width: 1px;
    border-bottom-color: rgba(88, 91, 112, 0.4);
}

.title-bar:hover {
    background-color: rgba(69, 71, 90, 1);
}

.title-bar-text {
    font-size: 11px;
    color: rgb(140, 143, 161);
}

/* 헤더 */
.dock-header {
    padding: 12px 16px;
