using UnityEditor;
using UnityEngine;
using UnityEngine.UI;
using UnityEngine.UIElements;

public static class DockSyncSetup
{
    [MenuItem("Tools/Setup DockSync Scene")]
    public static void SetupScene()
    {
        // ===== 1. uGUI Canvas (도킹 윈도우 시스템) =====
        var canvasGo = new GameObject("DockingCanvas");
        var canvas = canvasGo.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        canvas.sortingOrder = 0;
        var scaler = canvasGo.AddComponent<CanvasScaler>();
        scaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        scaler.referenceResolution = new Vector2(1920, 1080);
        canvasGo.AddComponent<GraphicRaycaster>();
        Undo.RegisterCreatedObjectUndo(canvasGo, "Create DockingCanvas");

        // --- 사이드바 (기존 uGUI) ---
        var sidebar = CreatePanel("Sidebar", canvasGo.transform,
            new Vector2(0, 0), new Vector2(0.18f, 1),
            new Color(0.14f, 0.14f, 0.18f));
        AddLabel("Navigation", sidebar.transform,
            TextAnchor.UpperCenter, 20, new Color(0.75f, 0.78f, 0.9f),
            new Vector2(0, 1), new Vector2(1, 1), new Vector2(0, -20), new Vector2(0, 40));

        // 사이드바 버튼들
        string[] menuItems = { "Dashboard", "Inventory", "Equipment", "Skills", "Map" };
        for (int i = 0; i < menuItems.Length; i++)
        {
            var btnGo = CreatePanel($"Btn_{menuItems[i]}", sidebar.transform,
                Vector2.zero, Vector2.zero,
                new Color(0.2f, 0.2f, 0.26f));
            var btnRect = btnGo.GetComponent<RectTransform>();
            btnRect.anchorMin = new Vector2(0.05f, 1);
            btnRect.anchorMax = new Vector2(0.95f, 1);
            btnRect.pivot = new Vector2(0.5f, 1);
            btnRect.sizeDelta = new Vector2(0, 40);
            btnRect.anchoredPosition = new Vector2(0, -70 - i * 48);
            AddLabel(menuItems[i], btnGo.transform,
                TextAnchor.MiddleLeft, 14, new Color(0.7f, 0.72f, 0.82f),
                Vector2.zero, Vector2.one, Vector2.zero, Vector2.zero,
                offsetMin: new Vector2(12, 0));
        }

        // --- 우측 패널 (기존 uGUI) ---
        var rightPanel = CreatePanel("RightPanel", canvasGo.transform,
            new Vector2(0.78f, 0), new Vector2(1, 1),
            new Color(0.14f, 0.14f, 0.18f));
        AddLabel("Details", rightPanel.transform,
            TextAnchor.UpperCenter, 20, new Color(0.75f, 0.78f, 0.9f),
            new Vector2(0, 1), new Vector2(1, 1), new Vector2(0, -20), new Vector2(0, 40));

        // --- 하단 바 (기존 uGUI) ---
        var bottomBar = CreatePanel("BottomBar", canvasGo.transform,
            new Vector2(0.18f, 0), new Vector2(0.78f, 0.04f),
            new Color(0.12f, 0.12f, 0.16f));
        AddLabel("Status: Online | FPS: 60", bottomBar.transform,
            TextAnchor.MiddleCenter, 12, new Color(0.45f, 0.48f, 0.58f),
            Vector2.zero, Vector2.one, Vector2.zero, Vector2.zero);

        // --- DockSlot (빈 패널 — UI Toolkit이 추적할 영역) ---
        var dockSlotGo = new GameObject("DockSlot", typeof(RectTransform));
        dockSlotGo.transform.SetParent(canvasGo.transform, false);
        var dockSlotRect = dockSlotGo.GetComponent<RectTransform>();
        // 앵커 사용하지 않고 절대 위치/크기 (드래그/리사이즈 가능하게)
        dockSlotRect.anchorMin = new Vector2(0.5f, 0.5f);
        dockSlotRect.anchorMax = new Vector2(0.5f, 0.5f);
        dockSlotRect.pivot = new Vector2(0.5f, 0.5f);
        dockSlotRect.sizeDelta = new Vector2(700, 500);
        dockSlotRect.anchoredPosition = new Vector2(-30, 20);

        // DockSlot 배경 (반투명 — UI Toolkit 뒤로 보임)
        var slotBg = dockSlotGo.AddComponent<UnityEngine.UI.Image>();
        slotBg.color = new Color(0.08f, 0.08f, 0.12f, 0.3f);
        slotBg.raycastTarget = false;

        // --- 드래그 타이틀바 (DockSlot 상단) ---
        var titleBar = new GameObject("TitleBar", typeof(RectTransform));
        titleBar.transform.SetParent(dockSlotGo.transform, false);
        var tbRect = titleBar.GetComponent<RectTransform>();
        tbRect.anchorMin = new Vector2(0, 1);
        tbRect.anchorMax = new Vector2(1, 1);
        tbRect.pivot = new Vector2(0.5f, 1);
        tbRect.sizeDelta = new Vector2(0, 28);
        tbRect.anchoredPosition = Vector2.zero;
        var tbImg = titleBar.AddComponent<UnityEngine.UI.Image>();
        tbImg.color = new Color(0.25f, 0.25f, 0.32f, 0.9f);
        var dragger = titleBar.AddComponent<DockSlotDragger>();
        var draggerSO = new SerializedObject(dragger);
        draggerSO.FindProperty("targetSlot").objectReferenceValue = dockSlotRect;
        draggerSO.ApplyModifiedProperties();

        AddLabel(":: Drag to Move ::", titleBar.transform,
            TextAnchor.MiddleCenter, 11, new Color(0.55f, 0.58f, 0.68f),
            Vector2.zero, Vector2.one, Vector2.zero, Vector2.zero);

        // --- 리사이즈 핸들 (DockSlot 우하단) ---
        var resizeHandle = new GameObject("ResizeHandle", typeof(RectTransform));
        resizeHandle.transform.SetParent(dockSlotGo.transform, false);
        var rhRect = resizeHandle.GetComponent<RectTransform>();
        rhRect.anchorMin = new Vector2(1, 0);
        rhRect.anchorMax = new Vector2(1, 0);
        rhRect.pivot = new Vector2(1, 0);
        rhRect.sizeDelta = new Vector2(24, 24);
        rhRect.anchoredPosition = Vector2.zero;
        var rhImg = resizeHandle.AddComponent<UnityEngine.UI.Image>();
        rhImg.color = new Color(0.5f, 0.55f, 0.7f, 0.8f);
        var resizer = resizeHandle.AddComponent<DockSlotResizer>();
        var resizerSO = new SerializedObject(resizer);
        resizerSO.FindProperty("targetSlot").objectReferenceValue = dockSlotRect;
        resizerSO.ApplyModifiedProperties();

        AddLabel("⤡", resizeHandle.transform,
            TextAnchor.MiddleCenter, 14, Color.white,
            Vector2.zero, Vector2.one, Vector2.zero, Vector2.zero);

        // ===== 2. UI Toolkit (DockSlot 추적) =====
        var uxmlGuids = AssetDatabase.FindAssets("DockSyncUI t:VisualTreeAsset");
        if (uxmlGuids.Length == 0)
        {
            Debug.LogError("DockSyncUI.uxml not found!");
            return;
        }
        var uxml = AssetDatabase.LoadAssetAtPath<VisualTreeAsset>(
            AssetDatabase.GUIDToAssetPath(uxmlGuids[0]));

        var panelGuids = AssetDatabase.FindAssets("t:PanelSettings",
            new[] { "Assets/DockSync" });
        PanelSettings panelSettings;
        if (panelGuids.Length > 0)
        {
            panelSettings = AssetDatabase.LoadAssetAtPath<PanelSettings>(
                AssetDatabase.GUIDToAssetPath(panelGuids[0]));
        }
        else
        {
            panelSettings = ScriptableObject.CreateInstance<PanelSettings>();
            panelSettings.scaleMode = PanelScaleMode.ScaleWithScreenSize;
            panelSettings.referenceResolution = new Vector2Int(1920, 1080);
            panelSettings.sortingOrder = 5; // uGUI(0)보다 높게
            AssetDatabase.CreateAsset(panelSettings, "Assets/DockSync/DockSyncPanelSettings.asset");
        }

        var uitkGo = new GameObject("DockSync_UIToolkit");
        var uiDoc = uitkGo.AddComponent<UIDocument>();
        uiDoc.panelSettings = panelSettings;
        uiDoc.visualTreeAsset = uxml;

        var dockSync = uitkGo.AddComponent<DockSync>();
        var syncSO = new SerializedObject(dockSync);
        syncSO.FindProperty("dockSlot").objectReferenceValue = dockSlotRect;
        syncSO.ApplyModifiedProperties();
        Undo.RegisterCreatedObjectUndo(uitkGo, "Create DockSync UIToolkit");

        // ===== 3. EventSystem =====
        if (Object.FindFirstObjectByType<UnityEngine.EventSystems.EventSystem>() == null)
        {
            var esGo = new GameObject("EventSystem");
            esGo.AddComponent<UnityEngine.EventSystems.EventSystem>();
            esGo.AddComponent<UnityEngine.EventSystems.StandaloneInputModule>();
            Undo.RegisterCreatedObjectUndo(esGo, "Create EventSystem");
        }

        // ===== 4. Camera =====
        if (Camera.main == null)
        {
            var camGo = new GameObject("Main Camera");
            camGo.tag = "MainCamera";
            var cam = camGo.AddComponent<Camera>();
            cam.orthographic = true;
            cam.backgroundColor = new Color(0.1f, 0.1f, 0.14f);
            cam.transform.position = new Vector3(0, 0, -10);
            Undo.RegisterCreatedObjectUndo(camGo, "Create Camera");
        }

        Selection.activeGameObject = dockSlotGo;
        Debug.Log("DockSync scene setup complete! Press Play to test.\n" +
                  "- Drag the title bar to move\n" +
                  "- Drag bottom-right handle to resize\n" +
                  "- UI Toolkit panel follows automatically");
    }

    private static GameObject CreatePanel(string name, Transform parent,
        Vector2 anchorMin, Vector2 anchorMax, Color color)
    {
        var go = new GameObject(name, typeof(RectTransform));
        go.transform.SetParent(parent, false);
        var rect = go.GetComponent<RectTransform>();
        rect.anchorMin = anchorMin;
        rect.anchorMax = anchorMax;
        rect.offsetMin = Vector2.zero;
        rect.offsetMax = Vector2.zero;
        var img = go.AddComponent<UnityEngine.UI.Image>();
        img.color = color;
        img.raycastTarget = false;
        return go;
    }

    private static void AddLabel(string text, Transform parent,
        TextAnchor align, int fontSize, Color color,
        Vector2 anchorMin, Vector2 anchorMax,
        Vector2 anchoredPos, Vector2 sizeDelta,
        Vector2? offsetMin = null)
    {
        var go = new GameObject("Label", typeof(RectTransform));
        go.transform.SetParent(parent, false);
        var rect = go.GetComponent<RectTransform>();
        rect.anchorMin = anchorMin;
        rect.anchorMax = anchorMax;
        if (sizeDelta != Vector2.zero)
        {
            rect.pivot = new Vector2(0.5f, 1);
            rect.sizeDelta = sizeDelta;
        }
        else
        {
            rect.offsetMin = offsetMin ?? Vector2.zero;
            rect.offsetMax = Vector2.zero;
        }
        rect.anchoredPosition = anchoredPos;

        var t = go.AddComponent<Text>();
        t.text = text;
        t.fontSize = fontSize;
        t.alignment = align;
        t.color = color;
        t.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        t.raycastTarget = false;
    }
}

