using UnityEngine;
using UnityEngine.UIElements;

/// <summary>
/// uGUI RectTransform ↔ UI Toolkit VisualElement 양방향 싱크.
/// 같은 reference resolution(1920x1080)을 사용하므로 직접 좌표 매핑.
/// </summary>
public class DockSync : MonoBehaviour
{
    [SerializeField] private RectTransform dockSlot;

    private UIDocument uiDocument;
    private VisualElement dockContainer;
    private Label sizeLabel;
    private Canvas canvas;

    // 드래그 상태
    private bool isDragging;
    private bool isResizing;
    private Vector2 dragStartMouse;
    private Vector2 dragStartPos;
    private Vector2 resizeStartMouse;
    private Vector2 resizeStartSize;

    void OnEnable()
    {
        uiDocument = GetComponent<UIDocument>();
        var root = uiDocument.rootVisualElement;
        dockContainer = root.Q<VisualElement>("dock-container");
        sizeLabel = root.Q<Label>("size-label");

        if (dockSlot != null)
            canvas = dockSlot.GetComponentInParent<Canvas>();

        // 타이틀바 드래그
        var titleBar = root.Q<VisualElement>("title-bar");
        titleBar.RegisterCallback<PointerDownEvent>(evt =>
        {
            isDragging = true;
            dragStartMouse = Input.mousePosition;
            dragStartPos = dockSlot.anchoredPosition;
            titleBar.CapturePointer(evt.pointerId);
            evt.StopPropagation();
        });
        titleBar.RegisterCallback<PointerUpEvent>(evt =>
        {
            isDragging = false;
            titleBar.ReleasePointer(evt.pointerId);
        });

        // 리사이즈 핸들
        var resizeHandle = root.Q<VisualElement>("resize-handle");
        resizeHandle.RegisterCallback<PointerDownEvent>(evt =>
        {
            isResizing = true;
            resizeStartMouse = Input.mousePosition;
            resizeStartSize = dockSlot.sizeDelta;
            resizeHandle.CapturePointer(evt.pointerId);
            evt.StopPropagation();
        });
