using UnityEngine;
using UnityEngine.UIElements;

/// <summary>
/// uGUI RectTransform ↔ UI Toolkit VisualElement 양방향 싱크.
/// UI Toolkit 타이틀바 드래그 → uGUI RectTransform 이동.
/// UI Toolkit 리사이즈 핸들 → uGUI RectTransform 크기 변경.
/// uGUI RectTransform 변경 → UI Toolkit 자동 추적.
/// </summary>
public class DockSync : MonoBehaviour
{
    [SerializeField] private RectTransform dockSlot;

    private UIDocument uiDocument;
    private VisualElement root;
    private VisualElement dockContainer;
    private Label sizeLabel;
    private Camera uiCamera;
    private Canvas canvas;

    // 드래그 상태
    private bool isDragging;
    private bool isResizing;
    private Vector2 dragStartMouse;
    private Vector2 dragStartPos;
    private Vector2 resizeStartMouse;
    private Vector2 resizeStartSize;

    void OnEnable()
    {
        uiDocument = GetComponent<UIDocument>();
        root = uiDocument.rootVisualElement;
        dockContainer = root.Q<VisualElement>("dock-container");
        sizeLabel = root.Q<Label>("size-label");

        if (dockSlot != null)
        {
            canvas = dockSlot.GetComponentInParent<Canvas>();
            uiCamera = canvas.renderMode == RenderMode.ScreenSpaceOverlay
                ? null : canvas.worldCamera;
        }

        // 타이틀바 드래그
        var titleBar = root.Q<VisualElement>("title-bar");
        titleBar.RegisterCallback<PointerDownEvent>(evt =>
        {
            isDragging = true;
            dragStartMouse = Input.mousePosition;
            dragStartPos = dockSlot.anchoredPosition;
            titleBar.CapturePointer(evt.pointerId);
            evt.StopPropagation();
        });
        titleBar.RegisterCallback<PointerUpEvent>(evt =>
        {
            isDragging = false;
            titleBar.ReleasePointer(evt.pointerId);
        });

        // 리사이즈 핸들
        var resizeHandle = root.Q<VisualElement>("resize-handle");
        resizeHandle.RegisterCallback<PointerDownEvent>(evt =>
        {
            isResizing = true;
            resizeStartMouse = Input.mousePosition;
            resizeStartSize = dockSlot.sizeDelta;
            resizeHandle.CapturePointer(evt.pointerId);
            evt.StopPropagation();
        });
        resizeHandle.RegisterCallback<PointerUpEvent>(evt =>
        {
            isResizing = false;
            resizeHandle.ReleasePointer(evt.pointerId);
        });

        // 카드 클릭
        root.Q<Button>("card-inventory").clicked += () => Debug.Log("Inventory clicked!");
        root.Q<Button>("card-equipment").clicked += () => Debug.Log("Equipment clicked!");
        root.Q<Button>("card-skills").clicked += () => Debug.Log("Skills clicked!");
        root.Q<Button>("card-quests").clicked += () => Debug.Log("Quests clicked!");
        root.Q<Button>("refresh-btn").clicked += () => Debug.Log("Refresh clicked!");
    }

    void Update()
    {
        if (dockSlot == null) return;

        float scaleFactor = canvas != null ? canvas.scaleFactor : 1f;

        if (isDragging)
        {
            Vector2 delta = ((Vector2)Input.mousePosition - dragStartMouse) / scaleFactor;
            dockSlot.anchoredPosition = dragStartPos + delta;
        }

        if (isResizing)
        {
            Vector2 delta = ((Vector2)Input.mousePosition - resizeStartMouse) / scaleFactor;
            var newSize = resizeStartSize + new Vector2(delta.x, -delta.y);
            newSize.x = Mathf.Max(250, newSize.x);
            newSize.y = Mathf.Max(200, newSize.y);
            dockSlot.sizeDelta = newSize;
        }
    }

    void LateUpdate()
    {
        if (dockSlot == null || dockContainer == null) return;

        // uGUI RectTransform → 스크린 좌표
        var corners = new Vector3[4];
        dockSlot.GetWorldCorners(corners);

        if (uiCamera != null)
        {
            for (int i = 0; i < 4; i++)
                corners[i] = uiCamera.WorldToScreenPoint(corners[i]);
        }

        // 스크린 좌표 → UI Toolkit 패널 좌표
        var panel = uiDocument.rootVisualElement.panel;
        var topLeft = RuntimePanelUtils.ScreenToPanel(panel,
            new Vector2(corners[1].x, corners[1].y));
        var bottomRight = RuntimePanelUtils.ScreenToPanel(panel,
            new Vector2(corners[3].x, corners[3].y));

        float w = bottomRight.x - topLeft.x;
        float h = bottomRight.y - topLeft.y;

        dockContainer.style.position = Position.Absolute;
        dockContainer.style.left = topLeft.x;
        dockContainer.style.top = topLeft.y;
        dockContainer.style.width = w;
        dockContainer.style.height = h;

        if (sizeLabel != null)
            sizeLabel.text = $"{Mathf.RoundToInt(w)} x {Mathf.RoundToInt(h)}";
    }
}

